import React, { useState, useEffect, useRef, Suspense } from "react";
import { Canvas } from "@react-three/fiber";
import { 
  OrbitControls, 
  useGLTF, 
  Environment, 
  PresentationControls,
  Stage,
  ContactShadows
} from "@react-three/drei";

const Model = () => {
  const modelPath = "http://localhost:3000/public/uploads/mustang.glb";
  const { scene: carScene } = useGLTF(modelPath);
  const { scene: islandScene } = useGLTF("http://localhost:3000/public/uploads/island.glb");
  const { scene: palmTree1 } = useGLTF("http://localhost:3000/public/uploads/palm_tree.glb");
  const { scene: palmTree2 } = useGLTF("http://localhost:3000/public/uploads/palm_tree.glb");

  return (
    <group>
      {/* Island base */}
      <primitive
        object={islandScene}
        scale={2}
        position={[0, -2, 0]}
      />

      {/* Car */}
      <primitive
        object={carScene}
        scale={0.03}
        position={[0, -1.2, 0]}  // Adjusted to sit on the island
      />

      {/* Palm trees */}
      <primitive
        object={palmTree1}
        scale={0.8}
        position={[-2, -1.2, -2]}  // Behind and to the left
        rotation={[0, Math.PI * 0.2, 0]}
      />
      <primitive
        object={palmTree2}
        scale={0.7}
        position={[2, -1.2, -2.5]}  // Behind and to the right
        rotation={[0, Math.PI * -0.3, 0]}
      />

      {/* Enhanced lighting for the scene */}
      <Stage
        environment="sunset"
        intensity={1.5}
        contactShadow={false}
        adjustCamera={false}
        preset="soft"
        shadows
      >
        {/* Stage contents remain empty as we're managing scene objects separately */}
      </Stage>

      {/* Enhanced shadows for all objects */}
      <ContactShadows
        position={[0, -1.8, 0]}
        opacity={0.4}
        scale={40}
        blur={2}
        far={4.5}
        color="#000000"
      />
    </group>
  );
};

const GameView = () => {
  const [isRotating, setIsRotating] = useState(false);
  const [isFullScreen, setIsFullScreen] = useState(false);
  const canvasRef = useRef(null);
  const controlsRef = useRef(null);

  const handleRotate = () => {
    setIsRotating(!isRotating);
  };

  const handleFullScreen = () => {
    const canvas = canvasRef.current;
    if (canvas) {
      if (!document.fullscreenElement) {
        const wrapper = document.createElement('div');
        wrapper.style.position = 'fixed';
        wrapper.style.top = '50%';
        wrapper.style.left = '50%';
        wrapper.style.transform = 'translate(-50%, -50%)';
        wrapper.style.width = '90vw';
        wrapper.style.height = '90vh';
        wrapper.style.backgroundColor = '#18181b';
        wrapper.style.borderRadius = '1rem';
        wrapper.style.overflow = 'hidden';
        wrapper.style.boxShadow = '0 0 0 100vw rgba(0, 0, 0, 0.8), 0 0 20px rgba(0, 0, 0, 0.5)';
        wrapper.style.zIndex = '9999';
        wrapper.style.border = '1px solid rgba(255, 255, 255, 0.1)';
        wrapper.style.padding = '1rem';
        wrapper.style.display = 'flex';
        wrapper.style.flexDirection = 'column';

        const header = document.createElement('div');
        header.style.position = 'absolute';
        header.style.top = '0';
        header.style.left = '0';
        header.style.right = '0';
        header.style.padding = '1rem';
        header.style.display = 'flex';
        header.style.justifyContent = 'space-between';
        header.style.alignItems = 'center';
        header.style.zIndex = '1';
        header.style.background = 'linear-gradient(to bottom, rgba(0,0,0,0.5), transparent)';

        const title = document.createElement('span');
        title.textContent = '3D View';
        title.style.color = 'white';
        title.style.fontWeight = 'bold';
        header.appendChild(title);

        const closeButton = document.createElement('button');
        closeButton.innerHTML = '<i class="fa-solid fa-times"></i>';
        closeButton.style.background = 'rgba(0, 0, 0, 0.5)';
        closeButton.style.border = '1px solid rgba(255, 255, 255, 0.1)';
        closeButton.style.color = 'white';
        closeButton.style.width = '32px';
        closeButton.style.height = '32px';
        closeButton.style.borderRadius = '50%';
        closeButton.style.cursor = 'pointer';
        closeButton.style.display = 'flex';
        closeButton.style.alignItems = 'center';
        closeButton.style.justifyContent = 'center';
        closeButton.style.transition = 'all 0.2s';
        closeButton.onmouseover = () => {
          closeButton.style.background = '#ef4444';
          closeButton.style.borderColor = '#ef4444';
        };
        closeButton.onmouseout = () => {
          closeButton.style.background = 'rgba(0, 0, 0, 0.5)';
          closeButton.style.borderColor = 'rgba(255, 255, 255, 0.1)';
        };

        const canvasContainer = document.createElement('div');
        canvasContainer.style.position = 'relative';
        canvasContainer.style.flex = '1';
        canvasContainer.style.width = '100%';
        canvasContainer.style.overflow = 'hidden';
        canvasContainer.className = 'canvas-container';

        // Store the original camera position and rotation
        const originalCameraState = {
          position: { ...canvas.__r3f?.state?.camera?.position },
          rotation: { ...canvas.__r3f?.state?.camera?.rotation }
        };

        canvas.style.position = 'absolute';
        canvas.style.width = '100%';
        canvas.style.height = '100%';
        canvas.style.top = '0';
        canvas.style.left = '0';

        if (canvas.__r3f?.state) {
          const state = canvas.__r3f.state;
          const container = canvasContainer;
          const aspect = container.clientWidth / container.clientHeight;

          state.camera.aspect = aspect;
          state.camera.updateProjectionMatrix();
        }

        wrapper.appendChild(header);
        canvasContainer.appendChild(canvas);
        wrapper.appendChild(canvasContainer);
        document.body.appendChild(wrapper);

        // Wait a frame to ensure the canvas is properly mounted
        requestAnimationFrame(() => {
          if (canvas.__r3f?.state?.camera) {
            canvas.__r3f.state.camera.updateProjectionMatrix();
          }
        });

        setIsFullScreen(true);

        const handleResize = () => {
          if (canvas.__r3f?.state?.camera) {
            canvas.__r3f.state.camera.aspect = canvasContainer.clientWidth / canvasContainer.clientHeight;
            canvas.__r3f.state.camera.updateProjectionMatrix();
          }
        };

        window.addEventListener('resize', handleResize);
        handleResize();

        const handleEsc = (e) => {
          if (e.key === 'Escape') {
            closeButton.click();
            window.removeEventListener('resize', handleResize);
            document.removeEventListener('keydown', handleEsc);
          }
        };
        document.addEventListener('keydown', handleEsc);

        // Store the cleanup function
        wrapper.cleanup = () => {
          const originalContainer = document.querySelector('.main-canvas-container');
          originalContainer.appendChild(canvas);
          document.body.removeChild(wrapper);

          // Restore original camera state if it was saved
          if (originalCameraState && canvas.__r3f?.state?.camera) {
            requestAnimationFrame(() => {
              canvas.__r3f.state.camera.updateProjectionMatrix();
            });
          }

          setIsFullScreen(false);
        };

        // Update close button to use cleanup
        closeButton.onclick = wrapper.cleanup;

      } else {
        const wrapper = canvas.parentElement.parentElement;
        if (wrapper.cleanup) {
          wrapper.cleanup();
        }
      }
    }
  };

  useEffect(() => {
    let animationFrameId;

    const rotateCamera = () => {
      if (isRotating && controlsRef.current) {
        controlsRef.current.autoRotate = true;
        controlsRef.current.autoRotateSpeed = 2.0;
        controlsRef.current.update();
      } else if (controlsRef.current) {
        controlsRef.current.autoRotate = false;
      }
      animationFrameId = requestAnimationFrame(rotateCamera);
    };

    rotateCamera();
    return () => {
      cancelAnimationFrame(animationFrameId);
      if (controlsRef.current) {
        controlsRef.current.autoRotate = false;
      }
    };
  }, [isRotating]);

  return (
    <div id="root">
      <section
        id="interactive_showcase"
        className="min-h-screen bg-black text-white py-20"
      >
        <div className="container mx-auto px-4">
          <div className="text-center max-w-3xl mx-auto mb-16">
            <h2 className="text-4xl md:text-5xl font-bold mb-4">
              Experience in 3D
            </h2>
            <p className="text-gray-400 text-lg">
              Explore every detail of our premium die-cast models with our
              interactive 3D viewer.
            </p>
          </div>

          <div className="grid md:grid-cols-2 gap-12 items-center">
            <div className="relative aspect-square rounded-2xl overflow-hidden group">
              <div className="absolute inset-0 bg-gradient-to-br from-black via-transparent to-red-500/10 z-10 pointer-events-none"></div>

              <div className="absolute inset-0 bg-gradient-to-br from-zinc-950 via-black to-red-950/20 main-canvas-container">
                <Canvas
                  ref={canvasRef}
                  camera={{ 
                    position: [15, 5, 15],  // Moved camera back and up slightly
                    fov: 45,
                    near: 0.1,
                    far: 1000
                  }}
                  shadows
                  dpr={[1, 2]}
                  className="w-full h-full"
                  style={{ 
                    width: '100%', 
                    height: '100%',
                    position: 'absolute',
                    top: 0,
                    left: 0
                  }}
                >
                  <color attach="background" args={['#1a1a2e']} />
                  <fog attach="fog" args={['#1a1a2e', 5, 30]} />

                  <Suspense fallback={null}>
                    <Model />
                    <Environment
                      preset="sunset"
                      background={false}
                      blur={0.5}
                    />

                    <spotLight
                      position={[10, 15, 10]}
                      angle={0.3}
                      penumbra={1}
                      intensity={2}
                      castShadow
                      color="#fdb813"  // Warm sunset color
                      shadow-bias={-0.0001}
                    />
                    <spotLight
                      position={[-15, 5, -10]}
                      angle={0.3}
                      penumbra={1}
                      intensity={1}
                      castShadow
                      color="#ff8c69"  // Coral color for sunset ambiance
                    />
                    <spotLight
                      position={[0, -5, 10]}
                      angle={0.5}
                      penumbra={0.5}
                      intensity={0.5}
                      castShadow
                      color="#00bfff"  // Ocean blue reflection
                    />
                    <rectAreaLight
                      position={[0, -2, 0]}
                      width={15}
                      height={15}
                      intensity={1}
                      color="#ffffff"
                      rotation={[-Math.PI / 2, 0, 0]}
                    />
                    <ambientLight intensity={0.3} />

                    <OrbitControls
                      ref={controlsRef}
                      enableZoom={true}
                      enablePan={false}
                      enableRotate={true}
                      minPolarAngle={Math.PI / 3}
                      maxPolarAngle={Math.PI / 2}
                      minAzimuthAngle={-Infinity}
                      maxAzimuthAngle={Infinity}
                      rotateSpeed={0.5}
                      zoomSpeed={0.5}
                      minDistance={10}  // Increased minimum distance
                      maxDistance={25}  // Increased maximum distance
                      target={[0, 0, 0]}
                      enableDamping={true}
                      dampingFactor={0.05}
                    />
                  </Suspense>
                </Canvas>
              </div>

              <div className="absolute bottom-6 left-1/2 -translate-x-1/2 flex gap-4 z-20">
                <button
                  onClick={handleRotate}
                  className="w-12 h-12 rounded-full bg-black/50 hover:bg-red-500 flex items-center justify-center backdrop-blur-sm transition-all border border-white/10"
                >
                  <i className={`fa-solid ${isRotating ? 'fa-pause' : 'fa-play'} text-white`}></i>
                </button>
                <button
                  onClick={handleFullScreen}
                  className="w-12 h-12 rounded-full bg-black/50 hover:bg-red-500 flex items-center justify-center backdrop-blur-sm transition-all border border-white/10"
                >
                  <i className={`fa-solid ${isFullScreen ? 'fa-compress' : 'fa-expand'} text-white`}></i>
                </button>
              </div>
            </div>

            <div className="space-y-8">
              <div className="space-y-4">
                <h3 className="text-3xl font-bold">GT Racing Pro X</h3>
                <p className="text-gray-400">
                  Experience the perfect blend of classic design and modern
                  engineering with our latest premium model.
                </p>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="p-4 rounded-xl bg-zinc-900">
                  <div className="text-red-500 mb-2">
                    <i className="fa-solid fa-ruler text-xl"></i>
                  </div>
                  <h4 className="font-semibold mb-1">Scale</h4>
                  <p className="text-gray-400">1:64</p>
                </div>
                <div className="p-4 rounded-xl bg-zinc-900">
                  <div className="text-red-500 mb-2">
                    <i className="fa-solid fa-paint-roller text-xl"></i>
                  </div>
                  <h4 className="font-semibold mb-1">Material</h4>
                  <p className="text-gray-400">Die-cast Metal</p>
                </div>
                <div className="p-4 rounded-xl bg-zinc-900">
                  <div className="text-red-500 mb-2">
                    <i className="fa-solid fa-certificate text-xl"></i>
                  </div>
                  <h4 className="font-semibold mb-1">Edition</h4>
                  <p className="text-gray-400">Limited Series</p>
                </div>
                <div className="p-4 rounded-xl bg-zinc-900">
                  <div className="text-red-500 mb-2">
                    <i className="fa-solid fa-box text-xl"></i>
                  </div>
                  <h4 className="font-semibold mb-1">Package</h4>
                  <p className="text-gray-400">Collector Box</p>
                </div>
              </div>

              <div className="flex gap-4">
                <button className="flex-1 py-3 bg-red-500 hover:bg-red-600 rounded-full transition-colors">
                  Add to Cart - $24.99
                </button>
                <button className="w-12 h-12 rounded-full border border-white/20 hover:border-white/40 flex items-center justify-center">
                  <i className="fa-regular fa-heart"></i>
                </button>
              </div>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
};

export default GameView;
